  );

  // Lock every editable line column EXCEPT discount + tax.
  const tableSO = this.getValue("table_so") || [];
  const lineColsToDisable = [
    "item_name",
    "item_id",
    "so_desc",
    "more_desc",
    "so_quantity",
    "so_item_uom",
    "so_gross",
    "so_amount",
