        item.item_batch_management,
        item.serial_number_management,
        item.stock_control,
        plantId,
        organizationId,
      );

      const finalQty = await convertBaseToAlt(
        initialQty,
        item.table_uom_conversion,
        defaultSalesDetail.alt_uom_id,
      );
